import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);
  const [requests, setRequests] = useState([]);

  const [search, setSearch] = useState("");
  const [date, setDate] = useState("");

  const [time1, setTime1] = useState("");
  const [time2, setTime2] = useState("");
  const [time3, setTime3] = useState("");

  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {

    const user = JSON.parse(localStorage.getItem("user"));

    const res = await axios.get(
      `http://localhost:5000/api/request/customer/${user.name}`
    );

    setRequests(res.data);
  };


  // SEARCH WORKERS
  const searchWorkers = async () => {

    const res = await axios.get(
      "http://localhost:5000/api/auth/workers"
    );

    const filtered = res.data.filter(w =>
      w.skills?.some(s =>
        s.toLowerCase().includes(search.toLowerCase())
      )
    );

    setWorkers(filtered);
  };


  // SEND REQUEST
  const sendRequest = async (worker) => {

    const user = JSON.parse(localStorage.getItem("user"));

    await axios.post(
      "http://localhost:5000/api/request/send",
      {
        customerName: user.name,
        labourId: worker._id,
        labourName: worker.name,
        workType: search,
        date,
        timings: [time1, time2, time3],
        status: "Pending",
        customerDecision: "Waiting"
      }
    );

    fetchRequests();
  };


  const getReq = (workerId) =>
    requests.find(r => r.labourId === workerId);


  // CUSTOMER ACTIONS
  const accept = async (id) => {
    await axios.put(
      `http://localhost:5000/api/request/customer-accept/${id}`
    );
    fetchRequests();
  };

  const reject = async (id) => {
    await axios.put(
      `http://localhost:5000/api/request/customer-reject/${id}`
    );
    fetchRequests();
  };


  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h2>Find Workers</h2>

        {/* SEARCH */}
        <div style={styles.searchBox}>

          <input
            placeholder="Work type"
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={styles.input}
          />

          <input
            type="date"
            onChange={e => setDate(e.target.value)}
            style={styles.input}
          />

          <button onClick={searchWorkers} style={styles.btn}>
            Search
          </button>

        </div>


        {/* WORKERS */}
        <div style={styles.grid}>

          {workers.map(w => {

            const req = getReq(w._id);

            return (

              <div key={w._id} style={styles.card}>

                <h3>{w.name}</h3>

                <p>{w.skills?.join(", ")}</p>

                <p>📍 {w.city}</p>

                <p>📞 {w.phone}</p>


                {/* STATUS DISPLAY */}
                {req && (

                  <div style={styles.statusBox}>

                    <p>
                      <b>Labour Status:</b> {req.status}
                    </p>

                    {req.status === "Accepted" && (
                      <p>Price: ₹{req.labourPrice}</p>
                    )}

                    <p>
                      <b>Customer Decision:</b> {req.customerDecision}
                    </p>

                  </div>

                )}


                {/* CUSTOMER ACCEPT / REJECT */}
                {req?.status === "Accepted" &&
                  req.customerDecision === "Waiting" && (

                  <div style={styles.row}>

                    <button
                      style={styles.acceptBtn}
                      onClick={() => accept(req._id)}
                    >
                      Accept
                    </button>

                    <button
                      style={styles.rejectBtn}
                      onClick={() => reject(req._id)}
                    >
                      Reject
                    </button>

                  </div>

                )}


                {!req && (
                  <button
                    style={styles.btn}
                    onClick={() => sendRequest(w)}
                  >
                    Send Request
                  </button>
                )}

              </div>
            );
          })}

        </div>

      </div>

    </div>
  );
}


const styles = {

  page: {
    fontFamily: "Arial",
    background: "#f5f7fb",
    minHeight: "100vh"
  },

  container: {
    padding: "30px"
  },

  searchBox: {
    display: "flex",
    gap: "10px",
    marginBottom: "20px"
  },

  input: {
    padding: "10px",
    border: "1px solid #ccc",
    borderRadius: "8px"
  },

  btn: {
    padding: "10px 15px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(250px,1fr))",
    gap: "15px"
  },

  card: {
    background: "white",
    padding: "15px",
    borderRadius: "10px",
    boxShadow: "0 2px 10px rgba(0,0,0,0.05)"
  },

  statusBox: {
    marginTop: "10px",
    padding: "10px",
    background: "#f1f5f9",
    borderRadius: "8px"
  },

  row: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "green",
    color: "white",
    border: "none",
    borderRadius: "8px"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "red",
    color: "white",
    border: "none",
    borderRadius: "8px"
  }

};
